import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void clearWinner() {
        // Uber=1000, Target=700 => top-1 is Uber
        String[][] txns = {{"Uber","800"},{"Target","300"},{"Uber","200"},{"Target","400"}};
        assertEquals(List.of("Uber"), new Solution().topSpendingMerchants(txns, 1));
    }

    @Test
    void tiebreakByNameAscending() {
        // Alpha=500, Beta=500, Gamma=200 => tie at 500; lex order: Alpha < Beta
        String[][] txns = {{"Alpha","500"},{"Beta","500"},{"Gamma","200"}};
        assertEquals(List.of("Alpha","Beta"), new Solution().topSpendingMerchants(txns, 2));
    }

    @Test
    void threeWayTieTopTwo() {
        // Zara=400, Amazon=400, Nike=400 => all tied; lex order: Amazon, Nike, Zara => top-2: Amazon, Nike
        String[][] txns = {{"Zara","400"},{"Amazon","400"},{"Nike","400"}};
        assertEquals(List.of("Amazon","Nike"), new Solution().topSpendingMerchants(txns, 2));
    }

    @Test
    void kEqualsAllMerchants() {
        // k equals number of merchants; full sorted list returned
        // Mall=200, Shop=100 => ["Mall","Shop"]
        String[][] txns = {{"Shop","100"},{"Mall","200"}};
        assertEquals(List.of("Mall","Shop"), new Solution().topSpendingMerchants(txns, 2));
    }

    @Test
    void multipleTransactionsPerMerchant() {
        // M1=250, M2=450, M3=300 => sorted desc: M2,M3,M1 => top-2: ["M2","M3"]
        String[][] txns = {{"M1","100"},{"M2","50"},{"M1","150"},{"M3","300"},{"M2","400"}};
        assertEquals(List.of("M2","M3"), new Solution().topSpendingMerchants(txns, 2));
    }

    @Test
    void singleTransaction() {
        String[][] txns = {{"Netflix","999"}};
        assertEquals(List.of("Netflix"), new Solution().topSpendingMerchants(txns, 1));
    }

    @Test
    void topOneFromThree() {
        // A=300, B=100, C=200 => sorted desc: A(300),C(200),B(100) => top-1: ["A"]
        String[][] txns = {{"A","300"},{"B","100"},{"C","200"}};
        assertEquals(List.of("A"), new Solution().topSpendingMerchants(txns, 1));
    }
}
